'use client';

import { useCompare } from '@/context/CompareContext';
import { GitCompare, X } from 'lucide-react';
import Link from 'next/link';
import { Button } from '@/components/ui/button';

export default function CompareFloatingAction() {
  const { compareIds, clearCompare } = useCompare();

  if (compareIds.length === 0) return null;

  return (
    <div
      className="fixed bottom-4 left-4 right-4 z-50 sm:bottom-8 sm:left-1/2 sm:right-auto sm:-translate-x-1/2"
      role="status"
      aria-live="polite"
    >
      <div className="flex flex-col items-stretch gap-3 rounded-2xl border border-white/10 bg-gray-900 p-3 text-white shadow-2xl backdrop-blur-xl sm:flex-row sm:items-center sm:gap-6 sm:p-4">
        <div className="flex items-center gap-3">
          <div className="rounded-lg bg-blue-600 p-2">
            <GitCompare className="h-5 w-5 text-white" aria-hidden />
          </div>
          <div>
            <p className="text-sm font-bold">
              {compareIds.length} College{compareIds.length !== 1 ? 's' : ''} Selected
            </p>
            <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">
              Ready to Compare
            </p>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <Link href="/compare" className="flex-1 sm:flex-none">
            <Button
              size="sm"
              className="w-full rounded-xl bg-white px-6 text-gray-900 hover:bg-gray-100 sm:w-auto"
            >
              View Comparison
            </Button>
          </Link>
          <button
            type="button"
            onClick={clearCompare}
            className="rounded-lg p-2 text-gray-400 transition-colors hover:bg-white/10 hover:text-white focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-white"
            aria-label="Clear college selection"
          >
            <X className="h-5 w-5" aria-hidden />
          </button>
        </div>
      </div>
    </div>
  );
}
